<?php
 namespace League\CommonMark\Block\Parser; use League\CommonMark\Block\Element\BlockQuote; use League\CommonMark\ContextInterface; use League\CommonMark\Cursor; final class BlockQuoteParser implements BlockParserInterface { public function parse(ContextInterface $context, Cursor $cursor): bool { if ($cursor->isIndented()) { return false; } if ($cursor->getNextNonSpaceCharacter() !== '>') { return false; } $cursor->advanceToNextNonSpaceOrTab(); $cursor->advanceBy(1); $cursor->advanceBySpaceOrTab(); $context->addBlock(new BlockQuote()); return true; } } 